public class NewModelFromSource_Action extends BaseAction {
  private static final Icon ICON = null;

  public NewModelFromSource_Action() {
    super("Models from Java Sources", "Adds BaseLanguage-authored models to context module from selected Java source files", ICON);
    this.setIsAlwaysVisible(false);
    this.setExecuteOutsideCommand(true);
  }
  @Override
  public boolean isDumbAware() {
    return true;
  }
  @Override
  public boolean isApplicable(AnActionEvent event, final Map<String, Object> _params) {
    if (!(event.getData(MPSCommonDataKeys.CONTEXT_MODULE) instanceof AbstractModule)) {
      return false;
    }

    String stereotype = NewModelFromSource_Action.this.getStereotype(event);
    if (stereotype == null) {
      return true;
    }
    for (String availableStereotype : SModelStereotype.values) {
      if (stereotype.equals(availableStereotype)) {
        return true;
      }
    }
    return false;
  }
  @Override
  public void doUpdate(@NotNull AnActionEvent event, final Map<String, Object> _params) {
    this.setEnabledState(event.getPresentation(), this.isApplicable(event, _params));
  }
  @Override
  protected boolean collectActionData(AnActionEvent event, final Map<String, Object> _params) {
    if (!(super.collectActionData(event, _params))) {
      return false;
    }
    {
      Frame p = event.getData(MPSCommonDataKeys.FRAME);
      if (p == null) {
        return false;
      }
    }
    {
      MPSProject p = event.getData(MPSCommonDataKeys.MPS_PROJECT);
      if (p == null) {
        return false;
      }
    }
    {
      Project p = event.getData(CommonDataKeys.PROJECT);
      if (p == null) {
        return false;
      }
    }
    {
      SModule p = event.getData(MPSCommonDataKeys.CONTEXT_MODULE);
      if (p == null) {
        return false;
      }
    }
    {
      Object p = event.getData(MPSCommonDataKeys.USER_OBJECT);
      if (p == null) {
        return false;
      }
    }
    return true;
  }
  @Override
  public void doExecute(@NotNull final AnActionEvent event, final Map<String, Object> _params) {
    final SRepository repository = event.getData(MPSCommonDataKeys.MPS_PROJECT).getRepository();
    Computable<Boolean> checkModelRoots = new Computable<Boolean>() {
      public Boolean compute() {
        return event.getData(MPSCommonDataKeys.CONTEXT_MODULE).getModelRoots().iterator().hasNext();
      }
    };
    ModelAccessHelper maHelper = new ModelAccessHelper(repository);

    if (!(maHelper.runReadAction(checkModelRoots))) {
      int code = JOptionPane.showConfirmDialog(event.getData(MPSCommonDataKeys.FRAME), "There are no model roots. Do you want to create one?", "", JOptionPane.YES_NO_OPTION);
      if (code == JOptionPane.YES_OPTION) {
        MPSPropertiesConfigurable configurable = new ModulePropertiesConfigurable(event.getData(MPSCommonDataKeys.CONTEXT_MODULE), event.getData(MPSCommonDataKeys.MPS_PROJECT));
        final SingleConfigurableEditor configurableEditor = new SingleConfigurableEditor(event.getData(CommonDataKeys.PROJECT), configurable, "#MPSPropertiesConfigurable");
        configurableEditor.show();
      } else {
        return;
      }
      if (!(maHelper.runReadAction(checkModelRoots))) {
        JOptionPane.showMessageDialog(event.getData(MPSCommonDataKeys.FRAME), "Can't create a model in solution with no model roots", "Can't create model", JOptionPane.ERROR_MESSAGE);
        return;
      }
    }

    FileChooserDescriptor descriptor = new FileChooserDescriptor(true, true, false, false, false, true);
    FileChooserDialog fileDialog = FileChooserFactory.getInstance().createFileChooser(descriptor, event.getData(CommonDataKeys.PROJECT), event.getData(MPSCommonDataKeys.FRAME));

    VirtualFile[] chosen = fileDialog.choose(event.getData(CommonDataKeys.PROJECT));

    if (chosen.length == 0) {
      return;
    }

    List<IFile> chosenIFiles = ListSequence.fromList(new ArrayList<IFile>(chosen.length));
    for (VirtualFile vfile : chosen) {
      ListSequence.fromList(chosenIFiles).addElement(event.getData(MPSCommonDataKeys.MPS_PROJECT).getFileSystem().fromVirtualFile(vfile));
    }
    final List<IFile> ifilesToParse = Sequence.fromIterable(JavaConvertUtil.flattenDirs(chosenIFiles)).toList();

    final JavaToMpsConverter parser = new JavaToMpsConverter(event.getData(MPSCommonDataKeys.CONTEXT_MODULE), repository, event.getData(CommonDataKeys.PROJECT).getService(MessagesViewTool.class).newHandler());


    ProgressManager.getInstance().run(new Task.Modal(null, "Convert to MPS", false) {
      public void run(@NotNull ProgressIndicator indicator) {
        parser.convertToMps(ifilesToParse, new ProgressMonitorAdapter(indicator));
      }
    });
    // FIXME MigrateSourcesToMPS doesn't need model write inside platform write to saveAll, which one is correct? Seems like this one, 
    // as saveAll saves models, but it's the same commit 661288c838da9be3a6d7352ed9804172fbb4f51f that changed both classes in a different way, on purpose, perhaps?
    // Another odd thing is that JavaToMpsConverter is capable to grab appropriate model access as needed (and does so), why it doesn't do that for saveAll?
    ApplicationManager.getApplication().runWriteAction(() -> event.getData(MPSCommonDataKeys.MPS_PROJECT).getRepository().getModelAccess().runWriteAction(() -> parser.saveAll()));
    // workaround for project pane not rebuilding itself when a model has been added
    // not in a command but in a write action
    ProjectPane.getInstance(event.getData(MPSCommonDataKeys.MPS_PROJECT)).rebuild();

    List<SModel> resulting = parser.getModels();
    if (ListSequence.fromList(resulting).isNotEmpty()) {
      SModel firstModel = ListSequence.fromList(resulting).first();
      ProjectPane.getInstance(event.getData(MPSCommonDataKeys.MPS_PROJECT)).selectModel(firstModel, false);
    }
  }
  protected String getStereotype(final AnActionEvent event) {
    if (event.getData(MPSCommonDataKeys.USER_OBJECT) instanceof StereotypeProvider) {
      return ((StereotypeProvider) event.getData(MPSCommonDataKeys.USER_OBJECT)).getStereotype();
    }
    return null;
  }
  protected boolean isStrict(final AnActionEvent event) {
    if (event.getData(MPSCommonDataKeys.USER_OBJECT) instanceof StereotypeProvider) {
      return ((StereotypeProvider) event.getData(MPSCommonDataKeys.USER_OBJECT)).isStrict();
    }
    return false;
  }
  protected String getNamespace(final AnActionEvent event) {
    return null;
  }
}
